import{_ as i,o as e,c as l,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const u=JSON.parse('{"title":"变易","description":"变易提醒人，《易》讲的不是静止分类，而是事物如何不断转化。","frontmatter":{"title":"变易","description":"变易提醒人，《易》讲的不是静止分类，而是事物如何不断转化。","category":"concept","aliases":["变易","易经变易","bian yi"]},"headers":[],"relativePath":"yijing/basics/concepts/bian-yi.md","filePath":"yijing/basics/concepts/bian-yi.md","lastUpdated":1777132262000}'),n={name:"yijing/basics/concepts/bian-yi.md"};function o(r,a,s,c,h,d){return e(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="变易" tabindex="-1">变易 <a class="header-anchor" href="#变易" aria-label="Permalink to &quot;变易&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>变易可以先理解为：世间事物不是停住不动，而是在关系、时势、位置中不断发生转化。</p><p>因此《易》关心的不是“固定答案”，而是：</p><ul><li>事物如何生变</li><li>变化如何有迹可循</li><li>人如何在变化中判断与应对</li></ul><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>把变易理解成“一切都不稳定，所以什么都不用学”</li><li>把变易读成只讲变化速度，而忽略变化的结构</li><li>只把“变”当新鲜感，而不看它背后的因势推移</li></ul><p>《易》之所以重“变”，不是为了让人漂浮，而是为了让人更会看结构中的转机。</p><h2 id="在原典中的语境" tabindex="-1">在原典中的语境 <a class="header-anchor" href="#在原典中的语境" aria-label="Permalink to &quot;在原典中的语境&quot;">​</a></h2><ul><li>《系辞》最能体现《易》对变化的总体理解。</li><li>六十四卦本身就是变化关系的结构化呈现。</li><li>逐卦逐爻的阅读，也是在看某一处境如何从一个阶段转入另一个阶段。</li></ul><h2 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h2><p>待补：后续可结合卦变、爻变与现实里的阶段转折继续补写。</p><h2 id="关联页面" tabindex="-1">关联页面 <a class="header-anchor" href="#关联页面" aria-label="Permalink to &quot;关联页面&quot;">​</a></h2><ul><li><a href="/Dao/yijing/basics/concepts/shi">时</a></li><li><a href="/Dao/yijing/basics/concepts/yin-yang">阴阳</a></li><li><a href="/Dao/yijing/basics/concepts/xiang-li-yong">象理用</a></li><li><a href="/Dao/topics/bian-yi">专题：变易</a></li></ul><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《周易》</li><li>《系辞上传》</li><li>《系辞下传》</li></ul>',16)])])}const b=i(n,[["render",o]]);export{u as __pageData,b as default};
